/**
 * Request body for ``POST /v1/assistants/<id>/push/dispatch/``.
 *
 * Mirrors the daemon ``PlatformPushAdapter`` invocation contract in the
 * APNs design doc (Phase 4). ``deep_link_metadata`` is accepted but
 * currently not consumed server-side; clients embed deep-link routing in
 * ``context_payload`` for v1.
 */
export type DispatchRequestRequest = {
    delivery_id: string;
    source_event_name: string;
    title: string;
    body: string;
    deep_link_metadata?: {
        [key: string]: unknown;
    };
    context_payload?: {
        [key: string]: unknown;
    };
    target_guardian_principal_id?: string | null;
};

/**
 * Response body for a successful dispatch (or idempotent replay).
 *
 * ``idempotent=True`` indicates the ``delivery_id`` was already claimed
 * within the 24h Redis TTL — no APNs send was performed on this call.
 */
export type DispatchResponse = {
    idempotent: boolean;
    tokens_sent: number;
};

/**
 * Response body when dispatch is intentionally skipped without
 * consuming the Redis idempotency slot.
 *
 * Sent with HTTP ``202 Accepted``. Possible ``skipped`` values:
 *
 * - ``"flag_off"``: the LaunchDarkly flag ``ios-remote-push-enabled``
 * is OFF for the request user.
 * - ``"no_tokens"``: the user has no registered iOS tokens at the time
 * of dispatch (e.g. fresh install before the device registers).
 *
 * In both cases the slot is preserved so a later retry with the same
 * ``delivery_id`` can deliver the notification.
 */
export type DispatchSkipped = {
    skipped: string;
};

/**
 * Response body when dispatch was attempted but **every** APNs send
 * raised (e.g. APNs outage, network partition).
 *
 * Sent with HTTP ``503 Service Unavailable``.  The Redis idempotency
 * slot is **released** before this response is returned so the caller
 * can immediately replay the same ``delivery_id`` instead of waiting
 * out the 24h TTL.
 */
export type DispatchUnavailable = {
    detail: string;
};

