/**
 * Request body for the unified signed-URL endpoint.
 *
 * Supports two operations:
 *
 * - ``operation="upload"`` — mint a signed PUT URL for uploading a new
 * ``.vbundle`` to object storage. Must not include ``bundle_key`` (the
 * key is server-generated so clients can't choose arbitrary paths).
 * - ``operation="download"`` — mint a signed GET URL for an existing
 * bundle identified by ``bundle_key``. Requires ``bundle_key``.
 *
 * ``content_type`` and ``content_length`` apply to uploads only and are
 * ignored on downloads.
 */
export type SignedUrlRequestRequest = {
    /**
     * Which signed URL to mint: 'upload' produces a PUT URL for a new bundle; 'download' produces a GET URL for an existing bundle referenced by bundle_key.
     *
     * * `upload` - upload
     * * `download` - download
     */
    operation: OperationEnum;
    /**
     * Required when operation == 'download'; forbidden otherwise.
     */
    bundle_key?: string;
    /**
     * MIME type the client will use when uploading. Applies only when operation == 'upload'.
     */
    content_type?: string;
    /**
     * Size of the bundle in bytes. When provided, the signed upload URL will require this exact Content-Length header. Applies only when operation == 'upload'.
     */
    content_length?: number;
    /**
     * Target runtime semver, applied only when operation == 'download'. When provided alongside an ExportJob with persisted compatibility bounds, the platform refuses to issue the signed URL if the target version is outside the bundle's [min, max] range. Omitted by legacy clients — backwards-compatible.
     */
    target_runtime_version?: string | null;
};

/**
 * Response body for the unified signed-URL endpoint.
 *
 * ``url`` is a V4 signed GCS URL: PUT for ``operation='upload'`` and GET
 * for ``operation='download'``. ``max_content_length`` is only populated
 * on uploads; download responses omit it.
 */
export type SignedUrlResponse = {
    /**
     * V4 signed GCS URL. PUT target for uploads; GET target for downloads.
     */
    url: string;
    /**
     * GCS object key of the bundle.
     */
    bundle_key: string;
    /**
     * ISO 8601 timestamp when the signed URL expires.
     */
    expires_at: string;
    /**
     * Maximum allowed bundle size in bytes. Only set for uploads.
     */
    max_content_length?: number;
};

